sql:
SELECT users.name, users.email
FROM users
WHERE users.user_id IN (SELECT book_recommendations.user_id FROM book_recommendations);

external_knowledge:
- Top-tier creators: Authors in the top 5;
- More than a handful: Published more than 3 books;
- Since the turn of the millennium: Published after 2000;
- Total works: Number of books published;
- Average critical acclaim: Average rating of the books.

sql:
SELECT a.name
FROM authors a
WHERE a.author_id IN (
    SELECT b.author_id
    FROM books b
    GROUP BY b.author_id
    HAVING COUNT(DISTINCT b.product_type) = (
        SELECT COUNT(DISTINCT product_type) FROM books
    )
);

SELECT DISTINCT b.title 
FROM books b
JOIN book_awards ba ON ba.book_id = b.book_id;

SELECT book_id, title, number_of_pages
FROM books
WHERE number_of_pages = (SELECT MAX(number_of_pages) FROM books);
